# ---------------------------------------------------------------------------
# Helpers
# ---------------------------------------------------------------------------

def _make_token(claims: dict) -> str:
    header = base64.urlsafe_b64encode(b'{"alg":"HS256"}').rstrip(b"=").decode()
    payload = base64.urlsafe_b64encode(json.dumps(claims).encode()).rstrip(b"=").decode()
    sig = base64.urlsafe_b64encode(b"fakesig").rstrip(b"=").decode()
    return f"{header}.{payload}.{sig}"


def _make_client(
    token_claims: Optional[dict] = None,
    workspace_id: str = "test-ws",
    api_url: str = "http://localhost:8080",
) -> Client:
    claims = token_claims or {"OrgID": "org-123", "UserID": "u1"}
    token = _make_token(claims)
    return Client(token=token, workspace_id=workspace_id, api_url=api_url)


# ============================================================================
# K1: Configurable query timeout
# ============================================================================


class TestQueryTimeout:
    """Issue: 60s hardcoded timeout caused large queries to silently fail.
    Fix: Added ``timeout`` parameter to ``client.query()``.
    """

    def test_default_timeout_is_60(self):
        """Default timeout remains 60s for backward compatibility."""
        client = _make_client()
        client._api_request = Mock(return_value={
            "columns": ["id"], "rows": [["r1"]], "row_count": 1,
        })

        client.query("SELECT 1")
        client._api_request.assert_called_once_with(
            "POST",
            "/workspaces/test-ws/tables/query",
            json_data={"query": "SELECT 1"},
            timeout=60,
        )

    def test_custom_timeout_forwarded_to_http(self):
        """Custom timeout is passed to _api_request as HTTP timeout."""
        client = _make_client()
        client._api_request = Mock(return_value={
            "columns": ["id"], "rows": [["r1"]], "row_count": 1,
        })

        client.query("SELECT COUNT(*) FROM big", timeout=300)
        client._api_request.assert_called_once_with(
            "POST",
            "/workspaces/test-ws/tables/query",
            json_data={
                "query": "SELECT COUNT(*) FROM big",
                "timeout_ms": 300000,
            },
            timeout=300,
        )

    def test_default_timeout_omits_timeout_ms_from_body(self):
        """Default timeout (60) does NOT send timeout_ms to backend."""
        client = _make_client()
        client._api_request = Mock(return_value={
            "columns": [], "rows": [], "row_count": 0,
        })

        client.query("SELECT 1")
        call_args = client._api_request.call_args
        body = call_args.kwargs.get("json_data") or call_args[1].get("json_data")
        assert "timeout_ms" not in body

    def test_query_still_returns_dicts(self):
        """Existing behavior preserved: query returns list of dicts."""
        client = _make_client()
        client._api_request = Mock(return_value={
            "columns": ["a", "b"],
            "rows": [[1, "x"], [2, "y"]],
            "row_count": 2,
        })

        result = client.query("SELECT a, b FROM t", timeout=120)
        assert result == [{"a": 1, "b": "x"}, {"a": 2, "b": "y"}]


# ============================================================================
# K4: Configurable PDF DPI
# ============================================================================


class TestPdfDpi:
    """Issue: 300 DPI rendering was 3.5x slower than 150 DPI with no control.
    Fix: Added ``dpi`` param to ``_normalize_pdf()``, default lowered to 150.
    """

    @pytest.fixture
    def pdf_path(self, tmp_path):
        fitz = pytest.importorskip("fitz")
        doc = fitz.open()
        page = doc.new_page(width=200, height=200)
        tw = fitz.TextWriter(page.rect)
        tw.append((50, 100), "test content", fontsize=14)
        tw.write_text(page)
        path = tmp_path / "test.pdf"
        doc.save(str(path))
        doc.close()
        return path

    @pytest.fixture
    def multi_page_pdf(self, tmp_path):
        fitz = pytest.importorskip("fitz")
        doc = fitz.open()
        for p in range(5):
            page = doc.new_page(width=612, height=792)
            tw = fitz.TextWriter(page.rect)
            for line in range(10):
                tw.append((72, 72 + line * 30), f"Page {p} line {line}", fontsize=12)
            tw.write_text(page)
        path = tmp_path / "multi.pdf"
        doc.save(str(path))
        doc.close()
        return path

    def test_default_dpi_produces_smaller_image_than_300(self, pdf_path):
        """150 DPI (default) produces a smaller image than 300 DPI."""
        client = _make_client()

        batches_default = list(client._normalize_pdf(pdf_path))
        batches_300 = list(client._normalize_pdf(pdf_path, dpi=300))

        img_default = batches_default[0]["image"][0]
        img_300 = batches_300[0]["image"][0]

        assert len(img_default) < len(img_300), (
            f"Default (150) DPI image ({len(img_default)}B) should be "
            f"smaller than 300 DPI ({len(img_300)}B)"
        )

    def test_72_dpi_smaller_than_150(self, pdf_path):
        """72 DPI produces even smaller images than 150 DPI."""
        client = _make_client()

        img_72 = list(client._normalize_pdf(pdf_path, dpi=72))[0]["image"][0]
        img_150 = list(client._normalize_pdf(pdf_path, dpi=150))[0]["image"][0]

        assert len(img_72) < len(img_150)

    def test_dpi_threaded_through_normalize_one_file(self, pdf_path):
        """pdf_dpi flows through _normalize_one_file to _normalize_pdf."""
        client = _make_client()

        batches_72 = client._normalize_one_file(str(pdf_path), 1000, 200, pdf_dpi=72)
        batches_300 = client._normalize_one_file(str(pdf_path), 1000, 200, pdf_dpi=300)

        assert len(batches_72[0]["image"][0]) < len(batches_300[0]["image"][0])

    def test_150_dpi_faster_than_300(self, multi_page_pdf):
        """150 DPI renders faster than 300 DPI (performance guard)."""
        client = _make_client()

        t0 = time.perf_counter()
        list(client._normalize_pdf(multi_page_pdf, dpi=150))
        t_150 = time.perf_counter() - t0

        t0 = time.perf_counter()
        list(client._normalize_pdf(multi_page_pdf, dpi=300))
        t_300 = time.perf_counter() - t0

        assert t_150 < t_300, (
            f"150 DPI ({t_150:.3f}s) should be faster than 300 DPI ({t_300:.3f}s)"
        )

    def test_text_extraction_works_at_any_dpi(self, pdf_path):
        """Text extraction is DPI-independent."""
        client = _make_client()

        batches_72 = list(client._normalize_pdf(pdf_path, dpi=72))
        batches_300 = list(client._normalize_pdf(pdf_path, dpi=300))

        text_72 = batches_72[0]["text"][0]
        text_300 = batches_300[0]["text"][0]

        assert "test content" in text_72
        assert text_72 == text_300


# ============================================================================
# Parallel thumbnail generation
# ============================================================================


class TestParallelThumbnails:
    """Issue: Serial thumbnail generation was a bottleneck for image ingests.
    Fix: ThreadPoolExecutor(max_workers=4) with executor.map().
    """

    @staticmethod
    def _make_images(n, size=(256, 256)):
        PIL = pytest.importorskip("PIL")
        from PIL import Image as PILImage
        images = []
        for i in range(n):
            img = PILImage.new("RGB", size, color=(i * 25 % 256, 0, 0))
            buf = io.BytesIO()
            img.save(buf, format="JPEG")
            images.append(buf.getvalue())
        return images

    def test_correct_count(self):
        """Parallel thumbnails produce one thumbnail per input image."""
        images = self._make_images(10)
        buffer = {"image": images}
        Client._generate_inline_thumbnails(buffer, ["image"])

        assert "image_thumbnail" in buffer
        assert len(buffer["image_thumbnail"]) == 10

    def test_thumbnails_are_valid_jpeg(self):
        """Each thumbnail is a non-empty JPEG."""
        images = self._make_images(5)
        buffer = {"image": images}
        Client._generate_inline_thumbnails(buffer, ["image"])

        for thumb in buffer["image_thumbnail"]:
            assert isinstance(thumb, bytes)
            assert len(thumb) > 0
            # JPEG magic bytes
            assert thumb[:2] == b"\xff\xd8"

    def test_thumbnails_smaller_than_originals(self):
        """Thumbnails (128x128) are smaller than 1024x1024 originals."""
        images = self._make_images(3, size=(1024, 1024))
        buffer = {"image": images}
        Client._generate_inline_thumbnails(buffer, ["image"])

        for orig, thumb in zip(images, buffer["image_thumbnail"]):
            assert len(thumb) < len(orig)

    def test_bad_data_produces_empty_placeholder(self):
        """Corrupt/empty data produces empty bytes, not an exception."""
        buffer = {"image": [b"not an image", b"", b"\x00\x01\x02"]}
        Client._generate_inline_thumbnails(buffer, ["image"])

        assert len(buffer["image_thumbnail"]) == 3
        assert all(t == b"" for t in buffer["image_thumbnail"])

    def test_missing_column_skipped(self):
        """If image column doesn't exist in buffer, it's silently skipped."""
        buffer = {"other_col": [1, 2, 3]}
        Client._generate_inline_thumbnails(buffer, ["image"])
        assert "image_thumbnail" not in buffer

    def test_parallel_faster_than_serial_on_batch(self):
        """Parallel is faster than serial for a batch of 50+ images."""
        PIL = pytest.importorskip("PIL")
        from PIL import Image as PILImage

        images = self._make_images(50, size=(512, 512))

        # Serial implementation
        def serial(vals):
            results = []
            for val in vals:
                try:
                    img = PILImage.open(io.BytesIO(val))
                    thumb = img.copy()
                    thumb.thumbnail((128, 128), PILImage.LANCZOS)
                    if thumb.mode in ("RGBA", "P"):
                        thumb = thumb.convert("RGB")
                    buf = io.BytesIO()
                    thumb.save(buf, format="JPEG", quality=85)
                    results.append(buf.getvalue())
                except Exception:
                    results.append(b"")
            return results

        t0 = time.perf_counter()
        serial(images)
        t_serial = time.perf_counter() - t0

        t0 = time.perf_counter()
        buffer = {"image": images}
        Client._generate_inline_thumbnails(buffer, ["image"])
        t_parallel = time.perf_counter() - t0

        assert t_parallel < t_serial, (
            f"Parallel ({t_parallel:.3f}s) should be faster than serial ({t_serial:.3f}s)"
        )
